def _install_embedded_module(name: str, source: str):
    mod = sys.modules.get(name)
    if mod is not None:
        return mod
    mod = types.ModuleType(name)
    mod.__file__ = f"<embedded:{name}>"
    sys.modules[name] = mod
    exec(source, mod.__dict__)
    return mod

