def _starts_with_role_name(text: str, role_names: Sequence[str], *, exclude: str = "") -> str:
    t = _normalize_text(text)
    for role in role_names:
        if role and role != exclude and t.startswith(role):
            return role
    return ""


@dataclass
class Entry:
    role: str
    text: str

    def is_stage(self) -> bool:
        return self.role == STAGE_ROLE

    def is_dialogue(self) -> bool:
        return bool(self.role) and self.role != STAGE_ROLE

    def is_plain(self) -> bool:
        return not self.role


def _normalize_text(text: str) -> str:
    text = str(text or "").replace("\u3000", " ")
    text = re.sub(r"[ \t]+", " ", text)
    return text.strip()


def _compact(text: str) -> str:
    return _normalize_text(text).replace(" ", "")


def _parse_structured_text(structured_text: str) -> List[Entry]:
    entries: List[Entry] = []
    for raw in str(structured_text or "").splitlines():
        line = _normalize_text(raw)
        if not line:
            continue
        if line.startswith(STAGE_ROLE + " "):
            entries.append(Entry(STAGE_ROLE, _normalize_text(line[len(STAGE_ROLE):])))
            continue
        if line == STAGE_ROLE:
            entries.append(Entry(STAGE_ROLE, ""))
            continue
        if " " in line:
            role, text = line.split(" ", 1)
            entries.append(Entry(_normalize_text(role), _normalize_text(text)))
        else:
            entries.append(Entry("", line))
    return entries


def _format_structured_text(entries: Sequence[Entry]) -> str:
    out: List[str] = []
    for e in entries:
        role = _normalize_text(e.role)
        text = _normalize_text(e.text)
        if not role and not text:
            continue
        if role:
            out.append(f"{role} {text}".rstrip())
        else:
            out.append(text)
    return "\n".join(out)


def _collect_role_names(entries: Sequence[Entry]) -> List[str]:
    seen = set()
    roles: List[str] = []
    for e in entries:
        if e.role and e.role != STAGE_ROLE and e.role not in seen:
            seen.add(e.role)
            roles.append(e.role)
    return sorted(roles, key=len, reverse=True)


def _looks_like_stage_text(text: str, role_names: Sequence[str]) -> bool:
    t = _normalize_text(text)
    if not t:
        return False
    if any(hint in t for hint in STAGE_HINTS):
        return True
    if t.startswith(("ノック音", "回想終了", "回想", "カッコウの鳴き声", "鳴き声")):
        return True
    # 地の文・場所文もト書き扱いに寄せる
    if t.endswith("。") and len(t) <= 18 and not re.search(r"[？?！!]", t):
        return True
    for role in role_names:
        if t.startswith(role + "は") or t.startswith(role + "が") or t.startswith(role + "も"):
            return True
    return False


def _remove_page_number_entries(entries: Sequence[Entry]) -> List[Entry]:
    out: List[Entry] = []
    for e in entries:
        text = _normalize_text(e.text)
        if (not e.role or e.role == STAGE_ROLE) and re.fullmatch(r"[0-9０-９ ]{1,6}", text):
            continue
        out.append(e)
    return out


def _fix_spaced_ascii(text: str) -> str:
    def repl(match: re.Match[str]) -> str:
        return match.group(0).replace(" ", "")

    return re.sub(r"(?<![A-Za-z0-9])(?:[A-Za-z0-9]\s+){1,}[A-Za-z0-9](?![A-Za-z0-9])", repl, text)


def _fix_split_katakana(text: str) -> str:
    prev = None
    cur = text
    for _ in range(4):
        if cur == prev:
            break
        prev = cur
        cur = re.sub(r"([ァ-ヶー]{1,8})\s+([ァ-ヶー]{1,8})", r"\1\2", cur)
    return cur


def _fix_scan_number_noise(text: str) -> str:
    t = _normalize_text(text)
    if not t:
        return t

    def _join_digit_spaces(match: re.Match[str]) -> str:
        return re.sub(r"(?<=\d)\s+(?=\d)", "", match.group(0))

    t = re.sub(
        rf"(?<!\d)(?:\d\s+){{1,5}}\d(?=(?:[{NUMERIC_UNITS}]|人の|人を|人が|人は))",
        _join_digit_spaces,
        t,
    )
    t = re.sub(r"(?<=[ぁ-んァ-ヶー一-龥々A-Za-z])\s*[0-9０-９]{1,3}\s*(?=[ぁ-んァ-ヶー一-龥々A-Za-z])", "", t)

    replacements = (
        (r"2020年の44月", "2020年の4月"),
        (r"2020年の月", "2020年の4月"),
        (r"あの年の44月から", "あの年の4月から"),
        (r"あの年の月から", "あの年の4月から"),
        (r"第回目の緊急事態宣言", "第1回目の緊急事態宣言"),
        (r"第回目", "第1回目"),
        (r"休憩室がつ", "休憩室が1つ"),
        (r"車に日乗った", "車に1日乗った"),
        (r"前方に人の作業員", "前方に5人の作業員"),
        (r"トロッコは人を轢き殺してしまう", "トロッコは5人を轢き殺してしまう"),
        (r"その先にいる人の作業員", "その先にいる1人の作業員"),
        (r"5人を救うために人を犠牲", "5人を救うために1人を犠牲"),
        (r"大体年前に", "大体5年前に"),
        (r"その人抑えておけば", "その2人抑えておけば"),
        (r"もう人お客様", "もう1人お客様"),
        (r"見て頂きたい件は", "見て頂きたい3件は"),
        (r"度としません", "2度としません"),
        (r"ワンちゃん匹", "ワンちゃん4匹"),
        (r"ニャンちゃん匹", "ニャンちゃん8匹"),
        (r"約2。3トン", "約2.3トン"),
        (r"駅って、", "駅8って、"),
        (r"駅って結構", "駅8って結構"),
        (r"駅の名物", "駅8の名物"),
        (r"1981年月", "1981年9月"),
        (r"1986年月", "1986年4月"),
        (r"駅裏号倉庫", "駅裏8号倉庫"),
        (r"僅か年間", "僅か5年間"),
        (r"例えば日間の全公演", "例えば43日間の全公演"),
        (r"閉館ラストは日間イベント", "閉館ラストは57日間イベント"),
        (r"震度の大きな地震", "震度7の大きな地震"),
        (r"要因のつ", "要因の1つ"),
        (r"事故物件は年経てば", "事故物件は3年経てば"),
        (r"自分人で逝っちゃって人・・・", "自分1人で逝っちゃって2人・・・"),
        (r"同じ場所で同じ縄でって人・・・", "同じ場所で同じ縄でって2人・・・"),
        (r"自分人で逝っちゃって人", "自分1人で逝っちゃって2人"),
        (r"震度の大きな地震", "震度7の大きな地震"),
    )
    for pat, rep in replacements:
        t = re.sub(pat, rep, t)
    return t


def _fix_text(text: str, *, route_family: str) -> str:
    t = _normalize_text(text)
    if not t:
        return t

    # textsource / direct は現段階では原文にない文字を補わない
    if route_family != "direct":
        for src, dst in SAFE_REPLACEMENTS:
            t = re.sub(src, dst, t)
        t = _fix_spaced_ascii(t)
        t = _fix_split_katakana(t)
        t = _fix_scan_number_noise(t)

    t = re.sub(r"[ 	]+", " ", t)
    return t.strip()


def _merge_consecutive_same_role(entries: Sequence[Entry], *, joiner: str = " ") -> List[Entry]:
    if not entries:
        return []
    out: List[Entry] = [Entry(entries[0].role, entries[0].text)]
    for cur in entries[1:]:
        prev = out[-1]
        if (
            cur.role
            and cur.role == prev.role
            and cur.role != STAGE_ROLE
        ):
            prev_text = _normalize_text(prev.text)
            cur_text = _normalize_text(cur.text)
            should_merge = False
            if prev_text and not re.search(r"[。！？!?…]$", prev_text):
                should_merge = True
            elif cur_text.startswith(("、", "，", ",", "。", "！", "？", "!", "?", "…", "」", "』", ")", "）")):
                should_merge = True
            if should_merge:
                prev.text = _normalize_text((prev.text + joiner + cur.text).strip())
                continue
        out.append(Entry(cur.role, cur.text))
    return out


def _rescue_stage_entries(entries: Sequence[Entry]) -> List[Entry]:
    role_names = _collect_role_names(entries)
    out: List[Entry] = []
    for e in entries:
        if e.is_stage() and e.text and not _looks_like_stage_text(e.text, role_names):
            out.append(Entry("", e.text))
        else:
            out.append(e)
    return out


def _split_inline_role_switches(entries: Sequence[Entry], *, route_family: str) -> List[Entry]:
    role_names = _collect_role_names(entries)
    if not role_names:
        return list(entries)

    out: List[Entry] = []
    for e in entries:
        if not e.is_plain():
            out.append(e)
            continue

        text = _normalize_text(e.text)
        split_done = False
        for role in role_names:
            if text.startswith(role + " "):
                out.append(Entry(role, _clean_split_after_text(text[len(role):])))
                split_done = True
                break

            if route_family == "direct":
                continue

            # OCR系だけ inline split を許すが、文中人名誤判定は抑える
            for prefix in INLINE_DIALOGUE_PREFIXES:
                probe = role + prefix
                if not text.startswith(probe):
                    continue
                if any(text.startswith(role + guard + prefix) for guard in ROLE_SPLIT_GUARD_PREFIXES):
                    continue
                if out and out[-1].is_dialogue() and _normalize_text(out[-1].text) in SHORT_PREV_TEXTS:
                    continue
                out.append(Entry(role, _clean_split_after_text(text[len(role):])))
                split_done = True
                break
            if split_done:
                break

        if not split_done:
            out.append(e)
    return out


def _join_broken_plain_lines(entries: Sequence[Entry], *, route_family: str) -> List[Entry]:
    out: List[Entry] = []
    role_names = _collect_role_names(entries)
    for cur in entries:
        if not out:
            out.append(Entry(cur.role, cur.text))
            continue
        prev = out[-1]

        if cur.is_plain() and prev.is_dialogue():
            # 新しい役名に見えるもの以外は前行へ吸収
            text = _normalize_text(cur.text)
            if not any(text.startswith(r + " ") for r in role_names):
                sep = "" if route_family == "direct" else " "
                prev.text = _normalize_text(prev.text + sep + cur.text)
                continue
        if cur.is_plain() and prev.is_stage():
            sep = "" if route_family == "direct" else " "
            prev.text = _normalize_text(prev.text + sep + cur.text)
            continue
        out.append(Entry(cur.role, cur.text))
    return out


def _collapse_stage_runs(entries: Sequence[Entry], *, route_family: str) -> List[Entry]:
    # direct は stage を独立させる。OCR は途中分断のみ軽く結合。
    if route_family == "direct":
        return list(entries)

    out: List[Entry] = []
    for cur in entries:
        if out and cur.is_stage() and out[-1].is_stage():
            prev = out[-1]
            if prev.text and not re.search(r"[。！？!?]$", prev.text):
                prev.text = _normalize_text(prev.text + " " + cur.text)
                continue
        out.append(Entry(cur.role, cur.text))
    return out


def _split_stage_sentences(entries: Sequence[Entry]) -> List[Entry]:
    out: List[Entry] = []
    for e in entries:
        if not e.is_stage():
            out.append(e)
            continue
        text = _normalize_text(e.text)
        if not text:
            out.append(e)
            continue
        pieces = [p.strip() for p in STAGE_SENTENCE_SPLIT_RE.split(text) if p.strip()]
        if len(pieces) <= 1:
            out.append(e)
            continue
        for piece in pieces:
            out.append(Entry(STAGE_ROLE, piece))
    return out


def _stage_text_from_dialogue(role: str, text: str) -> str:
    t = _normalize_text(text)
    if not t:
        return ""
    if not t.startswith(("は", "が", "も", "を", "に", "で", "と")):
        return ""
    probe = f"{role}{t}"
    head = probe[:24]
    if any(hint in head for hint in STAGE_HINTS):
        return probe
    return ""


def _split_dialogue_action_prefix(entries: Sequence[Entry]) -> List[Entry]:
    out: List[Entry] = []
    for e in entries:
        if not e.is_dialogue():
            out.append(e)
            continue
        stage_full = _stage_text_from_dialogue(e.role, e.text)
        if not stage_full:
            out.append(e)
            continue

        role_names = [x.role for x in entries if x.role and x.role != STAGE_ROLE]
        if not _looks_like_stage_text(stage_full, role_names):
            out.append(e)
            continue

        parts = [p.strip() for p in STAGE_SENTENCE_SPLIT_RE.split(stage_full) if p.strip()]
        if not parts:
            out.append(e)
            continue

        first = parts[0]
        rest = " ".join(parts[1:]).strip()
        out.append(Entry(STAGE_ROLE, first))
        if rest:
            # 残りは同役の台詞に戻す
            out.append(Entry(e.role, rest))
        continue
    return out


def _convert_action_dialogues_to_stage(entries: Sequence[Entry]) -> List[Entry]:
    role_names = _collect_role_names(entries)
    out: List[Entry] = []
    for e in entries:
        if not e.is_dialogue():
            out.append(e)
            continue
        stage_text = _stage_text_from_dialogue(e.role, e.text)
        if stage_text and _looks_like_stage_text(stage_text, role_names):
            out.append(Entry(STAGE_ROLE, stage_text))
        else:
            out.append(e)
    return out




def _merge_suspicious_role_switches(entries: Sequence[Entry], *, route_family: str) -> List[Entry]:
    if route_family != "direct":
        return list(entries)

    out: List[Entry] = []
    suspicious_starts = ("だから", "だって", "でも", "って", "ねえ", "でしょ", "じゃ", "だよ", "だね")
    for cur in entries:
        if not out:
            out.append(Entry(cur.role, cur.text))
            continue
        prev = out[-1]
        if (
            prev.is_dialogue() and cur.is_dialogue() and prev.role != cur.role
            and (_normalize_text(prev.text) in SHORT_PREV_TEXTS or len(_normalize_text(prev.text)) <= 2)
            and _normalize_text(cur.text).startswith(suspicious_starts)
        ):
            prev.text = _normalize_text(prev.text + cur.role + cur.text)
            continue
        out.append(Entry(cur.role, cur.text))
    return out

def _looks_like_dialogue_after_role(text: str) -> bool:
    t = _normalize_text(text)
    if not t:
        return False
    if t.startswith(ROLE_MENTION_BLOCKERS):
        return False
    return any(t.startswith(prefix) for prefix in ROLE_BOUNDARY_AFTER_PREFIXES)


def _looks_like_role_boundary(before: str, after: str) -> bool:
    left = _normalize_text(before)
    right = _normalize_text(after)
    if not right or not _looks_like_dialogue_after_role(right):
        return False
    if not left:
        return True
    if left.endswith(("。", "！", "？", "!", "?", "…", "・・・", "」", "』", ")", "）", ",", "，", "、")):
        return True
    if left in SHORT_PREV_TEXTS or len(left) <= 3:
        return True
    return False


def _find_embedded_role_boundary(text: str, role_names: Sequence[str], *, block_comma_boundary: bool = False) -> Tuple[int, str] | None:
    best: Tuple[int, str] | None = None
    probe_text = _normalize_text(text)
    if not probe_text:
        return None
    for role in role_names:
        start = 1
        while True:
            idx = probe_text.find(role, start)
            if idx < 0:
                break
            before = probe_text[:idx].rstrip()
            after = probe_text[idx + len(role):].lstrip()
            if block_comma_boundary and after.startswith(COMMA_PREFIXES):
                start = idx + len(role)
                continue
            if _looks_like_role_boundary(before, after):
                cand = (idx, role)
                if best is None or idx < best[0] or (idx == best[0] and len(role) > len(best[1])):
                    best = cand
                break
            start = idx + len(role)
    return best


def _clean_split_after_text(text: str) -> str:
    t = _normalize_text(text)
    t = re.sub(r"^[、，,]\s*", "", t)
    return t


def _find_space_delimited_role_boundary(text: str, role_names: Sequence[str]) -> Tuple[int, str] | None:
    probe_text = _normalize_text(text)
    if not probe_text:
        return None
    best: Tuple[int, str] | None = None
    for role in role_names:
        pattern = f" {role} "
        start = 0
        while True:
            idx = probe_text.find(pattern, start)
            if idx < 0:
                break
            before = probe_text[:idx].rstrip()
            after = probe_text[idx + len(pattern):].lstrip()
            if _looks_like_role_boundary(before, after):
                cand = (idx, role)
                if best is None or idx < best[0] or (idx == best[0] and len(role) > len(best[1])):
                    best = cand
                break
            start = idx + len(pattern)
    return best


def _split_embedded_role_switches(entries: Sequence[Entry], *, block_comma_boundary: bool = False, prefer_space_boundary: bool = False) -> List[Entry]:
    role_names = _collect_role_names(entries)
    if not role_names:
        return list(entries)

    out: List[Entry] = []
    for e in entries:
        if not e.role:
            out.append(e)
            continue

        if e.is_stage():
            text = _normalize_text(e.text)
            converted = False
            for role in role_names:
                after_text = text[len(role):]
                if block_comma_boundary and _normalize_text(after_text).startswith(COMMA_PREFIXES):
                    continue
                if text.startswith(role) and _looks_like_dialogue_after_role(after_text):
                    out.append(Entry(role, _clean_split_after_text(text[len(role):])))
                    converted = True
                    break
            if converted:
                continue
            out.append(e)
            continue

        current_role = e.role
        remaining = _normalize_text(e.text)
        guard = 0
        while remaining and guard < 8:
            guard += 1
            found = None
            if prefer_space_boundary:
                found = _find_space_delimited_role_boundary(remaining, role_names)
            if not found:
                found = _find_embedded_role_boundary(remaining, role_names, block_comma_boundary=block_comma_boundary)
            if not found:
                out.append(Entry(current_role, remaining))
                break
            idx, next_role = found
            before = _normalize_text(remaining[:idx])
            after = _clean_split_after_text(remaining[idx + len(next_role):])
            if before:
                out.append(Entry(current_role, before))
            current_role = next_role
            remaining = after
        else:
            if remaining:
                out.append(Entry(current_role, remaining))
    return out



def _looks_like_dialogue_continuation(text: str) -> bool:
    t = _normalize_text(text)
    if not t:
        return False
    if any(hint in t[:12] for hint in STAGE_HINTS):
        return False
    if t.startswith(DIALOGUE_CONTINUATION_PREFIXES):
        return True
    if re.match(r"^[ぁ-ん]{2,8}(?:[、。！？!?…])", t) and len(t) <= 48:
        return True
    if DIALOGUE_CONTINUATION_HEAD_RE.match(t) and len(t) <= 24 and re.search(r"[！？!?…]$", t):
        return True
    if t.startswith(("（", "(", "『", "「")):
        return True
    return False


def _rescue_dialogue_continuations(entries: Sequence[Entry], *, source_family: str) -> List[Entry]:
    if source_family not in DIRECTISH_SOURCE_FAMILIES:
        return list(entries)

    joiner = "" if source_family in DIRECTISH_SOURCE_FAMILIES else " "
    out: List[Entry] = []
    for cur in entries:
        if not out:
            out.append(Entry(cur.role, cur.text))
            continue
        prev = out[-1]
        cur_text = _normalize_text(cur.text)
        prev_text = _normalize_text(prev.text)
        special_tail_rescue = (
            prev.is_dialogue()
            and (cur.is_stage() or cur.is_plain())
            and not re.search(r"[。！？!?…]$", prev_text)
            and re.match(r"^[ぁ-ん]{1,8}", cur_text)
            and not any(hint in cur_text[:12] for hint in STAGE_HINTS)
        )
        if prev.is_dialogue() and (cur.is_stage() or cur.is_plain()) and (_looks_like_dialogue_continuation(cur_text) or special_tail_rescue):
            prev.text = _normalize_text(prev.text + joiner + cur.text)
            continue
        out.append(Entry(cur.role, cur.text))
    return out



def _starts_with_stage_style_role_reference(text: str, role_names: Sequence[str], *, exclude: str = "") -> str:
    role = _starts_with_role_name(text, role_names, exclude=exclude)
    if not role:
        return ""
    rest = _normalize_text(text[len(role):])
    if not rest:
        return ""
    if rest.startswith(ROLE_MENTION_BLOCKERS):
        return ""
    if rest.startswith((*COMMA_PREFIXES, "と", "や", "・", "が", "は", "を", "に", "へ", "も")):
        return role
    return ""

def _rescue_multi_role_stage_entries(entries: Sequence[Entry], *, route_family: str) -> List[Entry]:
    if route_family != "direct":
        return list(entries)

    role_names = _collect_role_names(entries)
    if not role_names:
        return list(entries)

    out: List[Entry] = []
    for e in entries:
        if not e.is_dialogue():
            out.append(e)
            continue

        text = _normalize_text(e.text)
        if not text:
            out.append(e)
            continue

        candidate = ""
        if text.startswith(("と", "や", "・")):
            tail = text[1:]
            if _starts_with_stage_style_role_reference(tail, role_names, exclude=e.role) and any(hint in text for hint in STAGE_HINTS):
                candidate = e.role + text
        elif text.startswith(COMMA_PREFIXES):
            tail = text[1:]
            if _starts_with_stage_style_role_reference(tail, role_names, exclude=e.role) and any(hint in text for hint in STAGE_HINTS):
                candidate = e.role + text
        elif _starts_with_stage_style_role_reference(text, role_names, exclude=e.role) and any(hint in text for hint in STAGE_HINTS):
            candidate = f"{e.role} {text}"

        if candidate and _looks_like_stage_text(candidate, role_names):
            out.append(Entry(STAGE_ROLE, candidate))
            continue

        out.append(e)
    return out

def _rescue_dialogue_from_stage(entries: Sequence[Entry]) -> List[Entry]:
    role_names = _collect_role_names(entries)
    if not role_names:
        return list(entries)

    out: List[Entry] = []
    for e in entries:
        if not e.is_stage():
            out.append(e)
            continue
        text = _normalize_text(e.text)
        rescued = False
        for role in role_names:
            if text.startswith(role) and _looks_like_dialogue_after_role(text[len(role):]):
                out.append(Entry(role, _clean_split_after_text(text[len(role):])))
                rescued = True
                break
        if not rescued:
            out.append(e)
    return out


def _extract_route_family(extras: Dict[str, object]) -> str:
    text = str(extras.get("copy_report_text") or extras.get("report_text") or "")
    route_match = re.search(r"^\[OCR_ROUTE\]\s*(.+)$", text, flags=re.MULTILINE)
    source_match = re.search(r"^\[OCR_SOURCE\]\s*(.+)$", text, flags=re.MULTILINE)

    direct_count = len(re.findall(r"=direct\b", route_match.group(1) if route_match else ""))
    ocr_count = len(re.findall(r"=ocr\b", route_match.group(1) if route_match else ""))
    scan_count = len(re.findall(r"=scan\b", source_match.group(1) if source_match else ""))

    if ocr_count == 0 and scan_count == 0:
        return "direct"
    if direct_count >= max(ocr_count, 1) * 3 and scan_count <= 1:
        return "direct"
    if ocr_count > direct_count or scan_count >= 2:
        return "ocr"
    return "mixed"


def _extract_source_family(extras: Dict[str, object]) -> str:
    text = str(extras.get("copy_report_text") or extras.get("report_text") or "")
    source_match = re.search(r"^\[OCR_SOURCE\]\s*(.+)$", text, flags=re.MULTILINE)
    source_line = source_match.group(1) if source_match else ""
    direct_count = len(re.findall(r"=direct\b", source_line))
    scan_count = len(re.findall(r"=scan\b", source_line))

    if scan_count == 0:
        return "direct"
    if direct_count == 0:
        return "scan"
    return "mixed"



def _count_non_stage_roles(entries: Sequence[Entry]) -> int:
    return len({e.role for e in entries if e.role and e.role != STAGE_ROLE})


def _reject_dialogue_entries_starting_with_comma(entries: Sequence[Entry], *, source_family: str) -> List[Entry]:
    if source_family not in DIRECTISH_SOURCE_FAMILIES:
        return list(entries)

    out: List[Entry] = []
    for cur in entries:
        cur_text = _normalize_text(cur.text)
        if cur.is_dialogue() and cur_text.startswith(COMMA_PREFIXES):
            payload = _normalize_text(f"{cur.role}{cur_text}")
            if out and out[-1].is_dialogue():
                out[-1].text = _normalize_text(out[-1].text + payload)
                continue
            out.append(Entry("", payload))
            continue
        out.append(Entry(cur.role, cur.text))
    return out


def _maybe_revert_direct_result(base_entries: Sequence[Entry], new_entries: Sequence[Entry], *, source_family: str) -> Sequence[Entry]:
    if source_family not in DIRECTISH_SOURCE_FAMILIES:
        return list(new_entries)

    base_role_count = _count_non_stage_roles(base_entries)
    new_role_count = _count_non_stage_roles(new_entries)
    base_count = len(base_entries)
    new_count = len(new_entries)

    if base_role_count >= 6 and new_role_count <= max(1, base_role_count // 2):
        return list(base_entries)
    if base_count >= 40 and new_count <= max(12, int(base_count * 0.5)):
        return list(base_entries)
    return list(new_entries)


def _postprocess_structured_text(structured_text: str, *, route_family: str, source_family: str) -> str:
    entries = _parse_structured_text(structured_text)
    entries = _remove_page_number_entries(entries)
    fix_route = "ocr" if source_family == "scan" else "direct"
    entries = [Entry(_normalize_text(e.role), _fix_text(e.text, route_family=fix_route)) for e in entries]

    # 共通の構造補正
    entries = _split_dialogue_action_prefix(entries)
    entries = _convert_action_dialogues_to_stage(entries)
    entries = _split_stage_sentences(entries)
    entries = _rescue_dialogue_from_stage(entries)
    entries = _split_embedded_role_switches(entries, block_comma_boundary=source_family in DIRECTISH_SOURCE_FAMILIES, prefer_space_boundary=source_family in DIRECTISH_SOURCE_FAMILIES)

    # textsource が主体の時は、v95 系の保守的な処理を優先して順序を崩さない
    if source_family == "direct":
        base_entries = list(entries)
        entries = _join_broken_plain_lines(entries, route_family="direct")
        entries = _merge_suspicious_role_switches(entries, route_family="direct")
        entries = _rescue_multi_role_stage_entries(entries, route_family="direct")
        entries = _split_embedded_role_switches(entries, block_comma_boundary=True, prefer_space_boundary=True)
        entries = _rescue_dialogue_continuations(entries, source_family=source_family)
        entries = _merge_consecutive_same_role(entries, joiner="")
        entries = _split_stage_sentences(entries)
        entries = _reject_dialogue_entries_starting_with_comma(entries, source_family=source_family)
        entries = _remove_page_number_entries(entries)
        entries = list(_maybe_revert_direct_result(base_entries, entries, source_family=source_family))
        return _format_structured_text(entries)

    # direct / scan 混在時は、OCR側の推測をかけ過ぎず conservative にまとめる
    if source_family == "mixed":
        base_entries = list(entries)
        entries = _join_broken_plain_lines(entries, route_family="direct")
        entries = _merge_suspicious_role_switches(entries, route_family="direct")
        entries = _rescue_dialogue_from_stage(entries)
        entries = _rescue_multi_role_stage_entries(entries, route_family="direct")
        entries = _split_embedded_role_switches(entries, block_comma_boundary=True, prefer_space_boundary=True)
        entries = _rescue_dialogue_continuations(entries, source_family=source_family)
        entries = _merge_consecutive_same_role(entries, joiner="")
        entries = _split_stage_sentences(entries)
        entries = _reject_dialogue_entries_starting_with_comma(entries, source_family=source_family)
        entries = _remove_page_number_entries(entries)
        entries = list(_maybe_revert_direct_result(base_entries, entries, source_family=source_family))
        return _format_structured_text(entries)

    entries = _rescue_stage_entries(entries)
    entries = _split_inline_role_switches(entries, route_family=route_family)
    entries = _join_broken_plain_lines(entries, route_family=route_family)
    entries = _collapse_stage_runs(entries, route_family=route_family)
    entries = _rescue_dialogue_from_stage(entries)
    entries = _split_embedded_role_switches(entries)
    entries = _split_stage_sentences(entries)
    entries = _merge_consecutive_same_role(entries)
    entries = _remove_page_number_entries(entries)
    return _format_structured_text(entries)


def _rewrite_copy_report(copy_report_text: str, structured_text: str, structured_count: int) -> str:
    if not copy_report_text:
        return structured_text

    lines = str(copy_report_text).splitlines()
    report_lines: List[str] = []
    for line in lines:
        if line.startswith("["):
            report_lines.append(line)
        else:
            break

    rewritten: List[str] = []
    for line in report_lines:
        if line.startswith("[OCR_REPORT]"):
            line = re.sub(r"mode=座標OCR（分割版・[^）]+）", f"mode=座標OCR（分割版・{VERSION_LABEL}）", line)
        if line.startswith("[OCR_COUNTS]"):
            line = re.sub(r"structured=\d+", f"structured={structured_count}", line)
        rewritten.append(line)

    return "\n".join(rewritten + [structured_text])





def parse_structured_text(structured_text: str):
    return _parse_structured_text(structured_text)


__all__ = [
    "parse_structured_text",
    "_parse_structured_text",
    "_postprocess_structured_text",
    "_rewrite_copy_report",
]


parse_structured_text = _parse_structured_text
